"use client";

import { Tick01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { cn } from "@/lib/utils";

interface StepperProps {
  steps: { title: string; icon: any }[];
  currentStep: number;
}

export const OnboardingStepper = ({ steps, currentStep }: StepperProps) => {
  return (
    <div className="flex w-full items-center justify-between px-2">
      {steps.map((step, index) => {
        const isCompleted = index < currentStep;
        const isActive = index === currentStep;

        return (
          <div key={step.title} className="flex flex-1 items-center last:flex-none">
            <div className="flex flex-col items-center gap-2">
              <div
                className={cn(
                  "relative flex size-10 items-center justify-center rounded-full border-2 transition-all duration-300",
                  isCompleted
                    ? "border-primary bg-primary text-primary-foreground shadow-[0_0_15px_-3px_rgba(var(--primary),0.5)]"
                    : isActive
                    ? "border-primary bg-background text-primary animate-pulse"
                    : "border-muted bg-muted/30 text-muted-foreground"
                )}
              >
                {isCompleted ? (
                  <HugeiconsIcon icon={Tick01Icon} size={18} strokeWidth={2.5} />
                ) : (
                  <HugeiconsIcon icon={step.icon} size={18} strokeWidth={isActive ? 2 : 1.5} />
                )}

                {isActive && (
                   <span className="absolute -inset-1 rounded-full border border-primary/30 animate-ping opacity-20" />
                )}
              </div>
              <span
                className={cn(
                  "text-[10px] font-medium transition-colors sm:text-xs",
                  isActive ? "text-primary" : "text-muted-foreground"
                )}
              >
                {step.title}
              </span>
            </div>

            {index < steps.length - 1 && (
              <div
                className={cn(
                  "mx-4 h-[2px] flex-1 rounded-full transition-all duration-500",
                  isCompleted ? "bg-primary" : "bg-muted/30"
                )}
              />
            )}
          </div>
        );
      })}
    </div>
  );
};

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { OnboardingStepper } from "../onboarding/onboarding-stepper";
import { ProfileStep } from "./steps/profile-step";
import { WorkspaceStep } from "./steps/workspace-step";
import { PreferencesStep } from "./steps/preferences-step";
import { UserIcon, Building01Icon, Settings01Icon, Camera01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";

const STEPS = [
  { title: "Profile", icon: UserIcon },
  { title: "Workspace", icon: Building01Icon },
  { title: "Account", icon: Settings01Icon },
];

export const OnboardingWizard = () => {
  const router = useRouter();
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    profile: {},
    workspace: {},
    preferences: {},
  });

  const nextStep = (stepData: any) => {
    const stepKeys = ["profile", "workspace", "preferences"];
    setFormData((prev) => ({
      ...prev,
      [stepKeys[currentStep]]: stepData,
    }));

    if (currentStep < STEPS.length - 1) {
      setCurrentStep((prev) => prev + 1);
    } else {
      handleComplete(stepData);
    }
  };

  const prevStep = () => {
    if (currentStep > 0) {
      setCurrentStep((prev) => prev - 1);
    }
  };

  const handleComplete = (finalData: any) => {
    // Merge all data
    const allData = {
      ...formData.profile,
      ...formData.workspace,
      ...formData.preferences,
      ...finalData,
    };
    console.log("Onboarding Complete:", allData);

    // Final redirection
    router.push("/dashboard/lifecycle");
  };

  return (
    <div className="flex min-h-screen items-center justify-center p-4">
      <div className="mx-auto w-full max-w-2xl border border-border/70 sm:rounded-2xl sm:bg-card sm:shadow-xl">
        <div className="border-b border-border/70 p-6 sm:p-8">
           <div className="flex items-center gap-3 mb-8">
              <div className="flex size-10 items-center justify-center rounded-xl bg-primary/10 text-primary">
                 <HugeiconsIcon icon={Camera01Icon} size={24} strokeWidth={1.5} />
              </div>
              <div>
                 <h1 className="text-xl font-semibold">Welcome to Murgo</h1>
                 <p className="text-sm text-muted-foreground">Let's set up your personal workspace</p>
              </div>
           </div>

           <OnboardingStepper steps={STEPS} currentStep={currentStep} />
        </div>

        <div className="p-6 sm:p-10">
          {currentStep === 0 && (
            <ProfileStep 
               onNext={nextStep} 
               defaultValues={formData.profile} 
            />
          )}
          {currentStep === 1 && (
            <WorkspaceStep 
               onNext={nextStep} 
               onBack={prevStep} 
               defaultValues={formData.workspace} 
            />
          )}
          {currentStep === 2 && (
            <PreferencesStep 
               onComplete={handleComplete} 
               onBack={prevStep} 
               defaultValues={formData.preferences} 
            />
          )}
        </div>

        <div className="border-t border-border/70 p-4 bg-muted/30 sm:rounded-b-2xl">
           <p className="text-center text-[10px] text-muted-foreground uppercase tracking-widest font-medium">
              Step {currentStep + 1} of {STEPS.length} — Murgo Onboarding Experience
           </p>
        </div>
      </div>
    </div>
  );
};

import { OnboardingWizard } from "@/components/onboarding/onboarding-wizard";

export const metadata = {
  title: "Onboarding | Murgo",
};

export default function OnboardingPage() {
  return <OnboardingWizard />;
}
